mapper.select:
SELECT

FROM hot_keyword
WHERE id = #{id}
  AND region = #{region}
LIMIT 1

SELECT COUNT(1)
FROM hot_keyword
WHERE region = #{region}
  AND LOWER(keyword) = LOWER(#{keyword})

    AND id != #{excludeId}

mapper.update:
UPDATE hot_keyword
SET keyword = #{keyword},
    sort = #{sortNo}
WHERE id = #{id}
  AND region = #{region}

UPDATE hot_keyword
SET enabled = #{enabled}
WHERE id = #{id}
  AND region = #{region}

mapper.delete:
DELETE FROM hot_keyword
WHERE id = #{id}
  AND region = #{region}
